const { createClient } = require('@graphprotocol/client');
const client = createClient('https://api.thegraph.com/subgraphs/name/my-subgraph');
const query = `{ events { id, blockNumber, timestamp } }`;
client.query(query).then(result => console.log(result.data.events));

